def test_required_fields():
    v = SchemaValidator()
    schema = Schema(type=SchemaType.OBJECT, required=['name', 'age'], properties={
        'name': Schema(type=SchemaType.STRING),
        'age': Schema(type=SchemaType.INTEGER)
    })
    result = v.validate({'name': 'Alice'}, schema)
    assert result.valid == False
    assert any('age' in e.message or 'age' in e.path for e in result.errors)

def test_valid_object():
    v = SchemaValidator()
    schema = Schema(type=SchemaType.OBJECT, required=['name'], properties={
        'name': Schema(type=SchemaType.STRING)
    })
    result = v.validate({'name': 'Alice'}, schema)
    assert result.valid == True

def test_nested_object_validation():
    v = SchemaValidator()
    address_schema = Schema(type=SchemaType.OBJECT, required=['city'], properties={
        'city': Schema(type=SchemaType.STRING)
    })
    schema = Schema(type=SchemaType.OBJECT, required=['address'], properties={
        'address': address_schema
    })
    result = v.validate({'address': {'city': 123}}, schema)
    assert result.valid == False

def test_complex_nested():
    v = SchemaValidator()
    schema = Schema(type=SchemaType.OBJECT, required=['users'], properties={
        'users': Schema(type=SchemaType.ARRAY, items=Schema(
            type=SchemaType.OBJECT, required=['name', 'score'], properties={
                'name': Schema(type=SchemaType.STRING, min_length=1),
                'score': Schema(type=SchemaType.NUMBER, minimum=0, maximum=100)
            }
        ))
    })
    valid_data = {'users': [{'name': 'Alice', 'score': 95}, {'name': 'Bob', 'score': 80}]}
    assert v.validate(valid_data, schema).valid == True
    invalid_data = {'users': [{'name': '', 'score': 150}]}
    result = v.validate(invalid_data, schema)
    assert result.valid == False
    assert len(result.errors) >= 2
